namespace sv_e7cd727ec2334f41ac2aff95e795c4ef.Services;

public enum Theme
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped service that holds per-circuit theme state.
/// Components subscribe to <see cref="OnChange"/> to react to updates.
/// </summary>
public sealed class ThemeService
{
    private Theme _theme = Theme.Light;
    private string _accentColor = "#0d6efd";

    public Theme Theme
    {
        get => _theme;
        set
        {
            if (_theme == value) return;
            _theme = value;
            NotifyChanged();
        }
    }

    public string AccentColor
    {
        get => _accentColor;
        set
        {
            if (_accentColor == value) return;
            _accentColor = value;
            NotifyChanged();
        }
    }

    public event Action? OnChange;

    /// <summary>
    /// Apply multiple changes and fire a single notification.
    /// </summary>
    public void Update(Theme theme, string accentColor)
    {
        var changed = _theme != theme || _accentColor != accentColor;
        _theme = theme;
        _accentColor = accentColor;
        if (changed) NotifyChanged();
    }

    private void NotifyChanged() => OnChange?.Invoke();
}

@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<span class="theme-indicator" style="color: @ThemeService.AccentColor;" title="Current theme">
    @GetIcon() @ThemeService.Theme
</span>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += OnThemeChanged;
    }

    private void OnThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private string GetIcon() => ThemeService.Theme switch
    {
        Theme.Dark => "🌙",
        Theme.System => "💻",
        _ => "☀️"
    };

    public void Dispose()
    {
        ThemeService.OnChange -= OnThemeChanged;
    }
}

@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<div class="theme-toggle">
    <span style="color: @ThemeService.AccentColor;">Theme: @ThemeService.Theme</span>
    <button class="btn btn-sm btn-outline-secondary ms-2" @onclick="CycleTheme">
        Toggle
    </button>
</div>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += OnThemeChanged;
    }

    private void CycleTheme()
    {
        ThemeService.Theme = ThemeService.Theme switch
        {
            Theme.Light => Theme.Dark,
            Theme.Dark => Theme.System,
            _ => Theme.Light
        };
    }

    private void OnThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        ThemeService.OnChange -= OnThemeChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="mb-3">
    <label class="form-label">Theme</label>
    <select class="form-select" style="max-width: 200px;"
            value="@ThemeService.Theme" @onchange="OnThemeSelected">
        @foreach (var t in Enum.GetValues<Theme>())
        {
            <option value="@t">@t</option>
        }
    </select>
</div>

<div class="mb-3">
    <label class="form-label">Accent Color</label>
    <input type="color" class="form-control form-control-color"
           value="@ThemeService.AccentColor" @onchange="OnColorChanged" />
</div>

<div class="mt-4 p-3 border rounded" style="border-color: @ThemeService.AccentColor !important;">
    <strong>Preview:</strong> Current theme is <em>@ThemeService.Theme</em>
    with accent <span style="color: @ThemeService.AccentColor;">@ThemeService.AccentColor</span>.
</div>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += OnThemeChanged;
    }

    private void OnThemeSelected(ChangeEventArgs e)
    {
        if (Enum.TryParse<Theme>(e.Value?.ToString(), out var theme))
        {
            ThemeService.Theme = theme;
        }
    }

    private void OnColorChanged(ChangeEventArgs e)
    {
